using namespace std;

const int MOD = 1e9 + 7;

long long solve(std::vector<long long> nums) {
    sort(nums.begin(), nums.end());
    int max_num = *max_element(nums.begin(), nums.end());
    vector<long long> dp(max_num + 1, 0);
    unordered_map<long long, long long> count;

    for (long long num : nums) {
        vector<long long> divisors;
        for (long long i = 1; i * i <= num; ++i) {
            if (num % i == 0) {
                divisors.push_back(i);
                if (i != num / i) {
                    divisors.push_back(num / i);
                }
            }
        }
        sort(divisors.begin(), divisors.end());
        reverse(divisors.begin(), divisors.end());

        long long total = 1; // count itself
        for (long long d : divisors) {
            if (d > max_num) continue;
            long long temp = dp[d];
            for (long long multiple = 2 * d; multiple <= max_num; multiple += d) {
                if (dp[multiple] > 0) {
                    temp = (temp - dp[multiple] + MOD) % MOD;
                }
            }
            dp[d] = (dp[d] + temp) % MOD;
            if (d == num) {
                total = temp;
            }
        }
        count[num] = (count[num] + total) % MOD;
    }

    long long result = 0;
    for (int g = 1; g <= max_num; ++g) {
        if (dp[g] == 0) continue;
        long long sum = 0;
        for (auto it = count.begin(); it != count.end(); ++it) {
            if (it->first % g == 0) {
                sum = (sum + it->second) % MOD;
            }
        }
        result = (result + g * sum) % MOD;
    }

    return result;
}
